// 三载体一致:产 xlsx 字节,零 style 足迹
import ExcelJS from 'https://cdn.jsdelivr.net/npm/exceljs@4.4.0/+esm';
const wb = new ExcelJS.Workbook();
for (const s of data.sheets) {
  const ws = wb.addWorksheet(s.name ?? 'Sheet1');
  if (s.columns) ws.columns = s.columns;
  for (const r of (s.rows ?? [])) ws.addRow(r);
  for (const m of (s.merges ?? [])) ws.mergeCells(m);
}
const buf = await wb.xlsx.writeBuffer();
const blob = new Blob([buf], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' });
